-- Refresh the "Web 2 Mob" ICP's sub-industries and their per-industry include
-- keywords with the health/wellness taxonomy (23 sub-industries).
-- Follows migration 044's scoping: include keywords are PER-industry (here);
-- the ICP-wide exclude list (icps.exclude_keywords) is left untouched.
--
-- Data edits normally happen in-app, but this is a bulk replace of every
-- sub-industry, so it ships as a one-shot migration. Guarded on the ICP
-- existing so it no-ops on a DB where the 043 seed hasn't been applied.

do $$
declare
  v_icp_id bigint;
begin
  select id into v_icp_id from icps where lower(name) = lower('Web 2 Mob');
  if v_icp_id is null then
    raise notice 'Web 2 Mob ICP not found; skipping industry refresh';
    return;
  end if;

  -- Replace the whole sub-industry set (no child tables reference these rows).
  delete from icp_industries where icp_id = v_icp_id;

end $$;
